#!/usr/bin/env python3
"""query_sbom.py — find deployed versions containing a specific package."""
import json, sys, os, glob

SBOM_DIR = os.environ.get("SBOM_ARCHIVE_DIR", "./sbom-archive")
PACKAGE  = sys.argv[1]  # e.g. "httpx"
MIN_VER  = sys.argv[2] if len(sys.argv) > 2 else None  # e.g. "0.27.0"

def load_sbom(path: str) -> dict:
    with open(path) as f:
        return json.load(f)

def find_package(sbom: dict, name: str) -> list[dict]:
    return [
        c for c in sbom.get("components", [])
        if c.get("name", "").lower() == name.lower()
    ]

results = []
for sbom_path in glob.glob(f"{SBOM_DIR}/*.cdx.json"):
    sbom = load_sbom(sbom_path)
    version_label = sbom.get("metadata", {}).get("component", {}).get("version", sbom_path)
    matches = find_package(sbom, PACKAGE)
    for m in matches:
        pkg_version = m.get("version", "unknown")
        # Flag if version is below the fixed version
        affected = True
        if MIN_VER:
            from packaging.version import Version
            affected = Version(pkg_version) < Version(MIN_VER)
        results.append({
            "image_version": version_label,
            "package": PACKAGE,
            "pkg_version": pkg_version,
            "affected": affected,
        })

if not results:
    print(f"Package '{PACKAGE}' not found in any SBOM in {SBOM_DIR}")
else:
    for r in results:
        status = "AFFECTED" if r["affected"] else "safe"
        print(f"[{status}] {r['image_version']}: {r['package']}@{r['pkg_version']}")
